// Mapeia colunas Apollo → LeadFinder
const items = $input.all();

const leads = items.map(item => {
  const row = item.json;

  // Concatena First Name + Last Name
  const firstName = (row['First Name'] || row['first name'] || '').trim();
  const lastName = (row['Last Name'] || row['last name'] || '').trim();
  const contato = [firstName, lastName].filter(Boolean).join(' ') || null;

  return {
    empresa: row['Company'] || row['Account Name'] || row['company'] || '',
    contato,
    email: row['Email'] || row['email'] || null,
    whatsapp: row['Mobile Phone'] || row['mobile phone'] || row['Phone'] || null,
    telefone: row['Work Phone'] || row['Work Direct Phone'] || row['work phone'] || null,
    linkedin: row['Person Linkedin URL'] || row['LinkedIn URL'] || row['linkedin url'] || null,
    website: row['Website'] || row['Company Website'] || row['website url'] || null,
    cidade: row['City'] || row['city'] || null,
    categoria: row['Industry'] || row['Keywords'] || row['industry'] || null,
    resumo_analitico: row['Title'] || row['Job Title'] || row['SEO Description'] || null,
    bairro: null,
    cnpj: null,
    instagram: null,
  };
}).filter(l => l.empresa.trim() !== '');

return [{ json: { leads, options: { defaultOrigem: 'apollo', defaultEstagio: 'Novo' } } }];

